function LoginView({ onLogin }) {
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");

  async function login() {
    if (!password.trim()) {
      setError("Password belum diisi.");
      return;
    }

    setBusy(true);
    setError("");

    try {
      const r = await fetch(apiUrl("/api/auth/login"), {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ password }),
      });

      const result = await r.json();

      if (!result.ok) {
        throw new Error(result.error || "Login gagal.");
      }

      const auth = {
        role: result.role || "admin",
        token: result.token,
        loginAt: new Date().toISOString(),
      };

      localStorage.setItem(AUTH_KEY, JSON.stringify(auth));
      onLogin(auth);
    } catch (err) {
      setError(err.message);
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="loginShell">
      <div className="loginCard">
        <div className="loginLogo">
          <Brain size={34} />
        </div>

        <div className="kicker">
          <ShieldCheck size={15} />
          EduBrain SMAN 9
        </div>

        <h1>Login Admin</h1>
        <p>
          Masuk untuk mengelola notulen, galeri aktivitas, dokumen, dan sinkronisasi database.
        </p>

        <div className="formRow">
          <label className="label">Password admin</label>
          <input
            className="input"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && login()}
            placeholder="Masukkan password admin"
            autoFocus
          />
        </div>

        {error && <div className="loginError">{error}</div>}

        <button className="btn primary full" onClick={login} disabled={busy}>
          <ShieldCheck size={18} />
          {busy ? "Memeriksa..." : "Masuk Admin"}
        </button>

        <div className="loginNote">
          Password disimpan di file <b>.env.local</b> pada server lokal.
        </div>
      </div>
    </div>
  );
}

